import{_ as a,o,c as r,a0 as t}from"./chunks/framework.BjpW4enL.js";const p=JSON.parse('{"title":"ADR: O Limite da Linguagem Natural e a Transição para Tensores Estruturais","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/TENSOR_FIRST_STRUCTURAL_RAG.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/TENSOR_FIRST_STRUCTURAL_RAG.md","lastUpdated":1783623176000}'),i={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/TENSOR_FIRST_STRUCTURAL_RAG.md"};function s(n,e,d,c,u,l){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="adr-o-limite-da-linguagem-natural-e-a-transicao-para-tensores-estruturais" tabindex="-1">ADR: O Limite da Linguagem Natural e a Transição para Tensores Estruturais <a class="header-anchor" href="#adr-o-limite-da-linguagem-natural-e-a-transicao-para-tensores-estruturais" aria-label="Permalink to &quot;ADR: O Limite da Linguagem Natural e a Transição para Tensores Estruturais&quot;">​</a></h1><p><strong>Status</strong>: Prospectivo (Roadmap v4.0)<br><strong>Date</strong>: 2026-03-14</p><h2 id="contexto" tabindex="-1">Contexto <a class="header-anchor" href="#contexto" aria-label="Permalink to &quot;Contexto&quot;">​</a></h2><p>Durante a implementação da Arquitetura v3.5 (Janela Temporal + AIE + HyDE), o operador identificou uma ineficiência matemática fundamental: a extrema dependência de &quot;Linguagem Natural&quot; para indexar e buscar lógica estritamente determinística (Código Fonte). Atualmente, forçamos um LLM a ler código, gerar um resumo em inglês/português, e vetorizar esse resumo. Isso é uma &quot;compressão com perda&quot; que introduz alucinação e latência onde deveria haver apenas correspondência de tensores.</p><h2 id="o-problema-do-text-embedding-para-codigo" tabindex="-1">O Problema do &quot;Text-Embedding&quot; para Código <a class="header-anchor" href="#o-problema-do-text-embedding-para-codigo" aria-label="Permalink to &quot;O Problema do &quot;Text-Embedding&quot; para Código&quot;">​</a></h2><p>Modelos de NLP (como <code>nomic-embed-text</code>) medem a proximidade de vocabulário e semântica coloquial. Eles falham em compreender que a função <code>A()</code> que recebe <code>(int, int)</code> e retorna <code>int</code> é matematicamente equivalente à função <code>B()</code> que recebe <code>(i32, i32) -&amp;gt; i32</code>, se os comentários ou nomes das variáveis forem diferentes.</p><p>Para contornar isso na v3.5, criamos &quot;muletas&quot;:</p><ol><li><strong>HyDE:</strong> Fazer a query do usuário virar pseudo-código antes da busca.</li><li><strong>AIE (Sonho):</strong> Fazer o código virar texto coloquial no banco.</li></ol><h2 id="a-solucao-proposta-v4-0-tensor-first" tabindex="-1">A Solução Proposta (v4.0 Tensor-First) <a class="header-anchor" href="#a-solucao-proposta-v4-0-tensor-first" aria-label="Permalink to &quot;A Solução Proposta (v4.0 Tensor-First)&quot;">​</a></h2><p>Para curar a dor da tradução humano-máquina no RAG de código, o sistema deve evoluir para a vetorização estrutural pura:</p><ol><li><strong>Substituição do Modelo de Embedding:</strong> Migrar do <code>nomic-embed-text</code> para modelos nativos de código (como <code>jina-embeddings-v2-base-code</code> ou <code>starcoder2</code>), que vetorizam a Árvore de Sintaxe Abstrata (AST) e o Grafo de Fluxo de Controle (CFG).</li><li><strong>Extração de AST no Rust (T1/T2):</strong> O Coordinator integrará <code>tree-sitter</code> para parsear os arquivos <code>.rs</code>, <code>.py</code>, <code>.ts</code>. O chunking deixará de ser por &quot;tamanho de string&quot; e passará a ser por &quot;nó da AST&quot; (classes, métodos inteiros).</li><li><strong>Grafos Tipados (T4):</strong> As arestas no Postgres deixarão de ser apenas k-NN semânticos (<code>hilbert_bridge</code>) para incluir grafos de execução reais: <code>calls</code>, <code>implements</code>, <code>imports</code>.</li></ol><h2 id="consequencias" tabindex="-1">Consequências <a class="header-anchor" href="#consequencias" aria-label="Permalink to &quot;Consequências&quot;">​</a></h2><ul><li>Fim da necessidade de processamento noturno em GPU para enriquecimento semântico de código.</li><li>Precisão cirúrgica na busca (a query &quot;Onde o banco é instanciado?&quot; navegará pelos tipos de retorno de <code>sqlx::PgPool</code>, ignorando textão).</li><li>Queda drástica no consumo de tokens e eliminação de alucinações de busca.</li></ul>',13)])])}const g=a(i,[["render",s]]);export{p as __pageData,g as default};
